// ─── STAGE 1: LEAD DISCOVERY ───
// Defines search queries to find AU Himalayan salt wholesale buyers
// across different buyer segments
const segments = [
  { type: 'Health Retailer', query: 'himalayan salt wholesale retailer Australia', keywords: ['health food', 'organic', 'natural'] },
  { type: 'Spa & Wellness', query: 'himalayan salt spa therapy Australia', keywords: ['wellness', 'spa', 'massage', 'therapy'] },
  { type: 'Food Distributor', query: 'himalayan salt food distributor Australia bulk', keywords: ['wholesale', 'distributor', 'food service'] },
  { type: 'Halotherapy', query: 'salt cave halotherapy Australia supplier', keywords: ['halotherapy', 'salt cave', 'salt room'] },
  { type: 'Gourmet / Restaurant', query: 'himalayan pink salt restaurant gourmet Australia', keywords: ['gourmet', 'restaurant', 'chef', 'cooking'] },
  { type: 'Animal Feed', query: 'himalayan salt lick animal feed Australia wholesale', keywords: ['livestock', 'animal', 'equine', 'farm'] },
  { type: 'Construction', query: 'himalayan salt bricks wall tiles Australia', keywords: ['construction', 'bricks', 'tiles', 'interior'] },
  { type: 'Bath & Beauty', query: 'himalayan bath salt wholesale Australia beauty', keywords: ['beauty', 'bath', 'skincare', 'cosmetic'] }
];

return segments.map(s => ({ json: s }));

// ─── STAGE 2: PARSE + NORMALISE PLACES RESULTS ───
const results = $json.results || [];
const segment = $('Define Lead Segments').item.json;

return results.map(place => ({
  json: {
    company_name: place.name,
    address: place.formatted_address,
    state: (() => {
      const states = ['NSW','VIC','QLD','WA','SA','TAS','ACT','NT'];
      return states.find(s => place.formatted_address?.includes(s)) || 'AU';
    })(),
    google_place_id: place.place_id,
    google_rating: place.rating || null,
    segment_type: segment.type,
    status: 'discovered',
    source: 'google_places',
    discovered_at: new Date().toISOString()
  }
}));

// ─── STAGE 3: ENRICH LEAD PROFILE ───
// Merges Google Places + Hunter.io + Apollo data into one lead record
const base = $('Parse Places Results').item.json;
const hunterData = $('Hunter.io Email Lookup').item.json;
const apolloData = $('Apollo.io Contact Search').item.json;

const emails = hunterData?.data?.emails || [];
const contact = apolloData?.people?.[0] || {};

// Map segment to product interest from catalogue
const productMap = {
  'Health Retailer': 'Food Grade Salt (Fine/Coarse Pink - P601-P609), Bath Salt',
  'Spa & Wellness': 'Bath & Asthma Salt, Salt Lamps (home décor), Halo Therapy Articles',
  'Food Distributor': 'Food Grade Salt bulk (P601-P609), Kitchenware & Seasoning',
  'Halotherapy': 'Halo Salt Therapy Articles (P59-P60), Salt Bricks (Construction)',
  'Gourmet / Restaurant': 'Food Grade Salt Fine/Coarse, Kitchenware & Seasoning, Salt Grinders',
  'Animal Feed': 'Animal Lick Articles (P68-P69)',
  'Construction': 'Construction Articles - Salt Bricks/Tiles (P64-P67)',
  'Bath & Beauty': 'Industrial, Bath & Asthma Salt Articles (P70-P74)'
};

const enriched = {
  ...base,
  contact_name: contact.name || emails[0]?.first_name ? `${emails[0]?.first_name || ''} ${emails[0]?.last_name || ''}`.trim() : 'Procurement Team',
  contact_title: contact.title || 'Buyer/Owner',
  email: contact.email || emails[0]?.value || null,
  email_confidence: emails[0]?.confidence || null,
  linkedin_url: contact.linkedin_url || null,
  company_size: contact.organization?.estimated_num_employees || 'Unknown',
  website: contact.organization?.website_url || hunterData?.data?.domain || null,
  product_interest: productMap[base.segment_type] || 'General Himalayan Salt Products',
  status: 'enriched',
  enriched_at: new Date().toISOString(),
  outreach_sent: false,
  reply_received: false,
  follow_up_count: 0
};

return [{ json: enriched }];

// ─── STAGE 4: PERSONALISED OUTREACH COPY GENERATOR ───
// Creates tailored email + LinkedIn message based on lead segment
const lead = $json;

const firstName = lead.contact_name?.split(' ')[0] || 'there';
const company = lead.company_name;
const segment = lead.segment_type;
const products = lead.product_interest;
const state = lead.state;

// ── EMAIL SUBJECT LINES (A/B variants) ──
const subjects = {
  'Health Retailer': `Direct Himalayan Rock Salt Supply for ${company} — AU Importer`,
  'Spa & Wellness': `Premium Himalayan Salt Products for ${company} — Direct from Mine`,
  'Food Distributor': `Bulk Himalayan Rock Salt — Competitive Wholesale Pricing for ${state}`,
  'Halotherapy': `Himalayan Salt Therapy Supplies — Direct Importer, ${state}`,
  'Gourmet / Restaurant': `Himalayan Pink Salt for ${company} — Food Grade, Direct Supply`,
  'Animal Feed': `Himalayan Salt Licks — Bulk Wholesale for ${state} Distributors`,
  'Construction': `Himalayan Salt Bricks & Construction Articles — ${state} Importer`,
  'Bath & Beauty': `Himalayan Bath Salt Wholesale — Private Label Available, ${state}`
};

// ── EMAIL BODY ──
const emailBody = `Hi ${firstName},

I hope this finds you well. My name is [YOUR NAME] and I represent The Holy Minerals — a direct importer of Himalayan Rock Salt products sourced from the Khewra Salt Mine in Pakistan, the world's second largest salt mine.

I noticed ${company} works in the ${segment.toLowerCase()} space, and I believe we can add real value to your supply chain. We carry a full range that would suit your needs:

📦 Relevant to you: ${products}

Why source through us?
• Direct mine-to-AU importer — no middlemen, sharper pricing
• Full product range: food grade, lamps, bath, construction, halotherapy & more
• Flexible MOQs — suitable for both retail and wholesale volumes
• White label packaging available — your brand, our product
• Australian-based operations with fast local fulfilment

I'd love to send you our full product catalogue and a tailored wholesale price list. If you're currently sourcing Himalayan salt, I'm confident we can offer better pricing or range.

Would you be open to a quick 15-minute call this week?

Warm regards,
[YOUR NAME]
The Holy Minerals
[YOUR PHONE]
[YOUR EMAIL]

P.S. We also offer white label solutions — if you'd like products packaged under your own brand, we can discuss that too.`;

// ── LINKEDIN MESSAGE (short, casual) ──
const linkedinMsg = `Hi ${firstName}, I'm a direct importer of Himalayan Rock Salt into Australia (The Holy Minerals) — we carry food grade, lamps, bath, halotherapy and construction products directly from the Khewra Mine. Given what ${company} does, I thought there might be a fit. Happy to send our catalogue + wholesale pricing if you're interested? Also offer white label if that's useful.`;

// ── FOLLOW-UP EMAIL (Day 5) ──
const followUp1 = `Hi ${firstName},

Just following up on my note from earlier this week about Himalayan Rock Salt supply for ${company}.

I wanted to share that we currently have competitive pricing on our most popular lines — food grade pink salt (fine & coarse), salt lamps, and bath salts — with Australian stock available for fast delivery.

Would it be worth a quick chat? Happy to work around your schedule.

Best,
[YOUR NAME] | The Holy Minerals`;

// ── FOLLOW-UP 2 (Day 12) ──
const followUp2 = `Hi ${firstName},

Last touch from me — I don't want to clog your inbox!

If Himalayan salt sourcing isn't on your radar right now, no worries at all. But if timing changes or you'd like our catalogue for future reference, just reply and I'll send it through.

All the best,
[YOUR NAME] | The Holy Minerals`;

return [{
  json: {
    ...lead,
    outreach: {
      email_subject: subjects[segment] || `Himalayan Rock Salt Supply — Direct AU Importer`,
      email_body: emailBody,
      linkedin_message: linkedinMsg,
      follow_up_day5: followUp1,
      follow_up_day12: followUp2
    },
    status: 'ready_to_send'
  }
}];

// Log leads without email for manual LinkedIn outreach
const lead = $json;
console.log(`[LinkedIn Queue] ${lead.company_name} — ${lead.linkedin_url || 'Search manually'} — ${lead.outreach?.linkedin_message}`);
return [{ json: { ...lead, status: 'linkedin_queue' } }];
